#include <stdio.h>
#include <inttypes.h>
int main(){
    int T; if(scanf("%d", &T)!=1) return 0;
    while(T--){
        int64_t N, K; scanf("%" PRId64 " %" PRId64, &N, &K);
        int64_t ans = (N + K) / (K + 1);
        printf("%" PRId64 "\n", ans);
    }
    return 0;
}

