#!/usr/bin/env python3
import sys
def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out = []
    for _ in range(T):
        N = int(next(it)); K = int(next(it))
        ans = (N + K) // (K + 1)
        out.append(str(ans))
    sys.stdout.write('\n'.join(out))
if __name__ == "__main__":
    main()

